## 4.逻辑

```javascript
//index.js
//获取应用实例
const app = getApp()

Page({
  data: {
    queryNumber: -1,
    isShowResult: false,
    text: ''
  },

  onLoad: function () {

  },

  bindInput: function (e) {
    this.setData({
      queryNumber: e.detail.value
    })
  },

  bindInputText: function (e) {
    this.setData({
      text: e.detail.value
    })
  },

  query: function () {
    if (this.data.queryNumber <= 0) {
      wx.showToast({
        title: '查询码不正确！',
        icon: 'none'
      });
      return
    }

    var that = this;
    wx.showLoading({
      title: '请稍后...',
    })
    wx.request({
      url: 'https://wycode.cn/web/api/public/clipboard/query',
      data: { 'id': this.data.queryNumber },
      success: function (res) {
        if (!res.data.success || res.data.data == null) {
          wx.showToast({
            title: '查询码不正确！',
            icon: 'none'
          });
        } else {
          that.setData({
            isShowResult: true,
            queryNumber: res.data.data.id,
            text: res.data.data.content
          });
        }
      },
      fail: function (res) {
        wx.showToast({
          title: res,
          icon: 'none'
        });
      },
      complete:function(){
        wx.hideLoading();
      }
    });

  },

  create: function () {
    var that = this;
    wx.showLoading({
      title: '请稍后...',
    })
    wx.request({
      url: 'https://wycode.cn/web/api/public/clipboard/create',
      method: 'POST',
      success: function (res) {

        that.setData({
          isShowResult: true,
          queryNumber: res.data.data.id,
          text: res.data.data.content
        });

      },
      fail: function (res) {
        wx.showToast({
          title: res.errMsg,
          icon: 'none'
        });
      },
      complete:function(){
        wx.hideLoading();
      }
    });
  },

  save: function () {
    var that = this;
    wx.showLoading({
      title: '请稍后...',
    })
    wx.request({
      url: 'https://wycode.cn/web/api/public/clipboard/save',
      method: 'POST',
      data:{
        id: that.data.queryNumber,
        content: that.data.text
      },
      header: {
        'content-type': 'application/x-www-form-urlencoded'
      },
      success: function (res) {

        that.setData({
          isShowResult: false,
          queryNumber: res.data.data.id,
          text: res.data.data.content
        });
        wx.showToast({
          title: '保存成功！',
          icon: 'success'
        });

      },
      fail: function (res) {
        wx.showToast({
          title: res.errMsg,
          icon: 'none'
        });
      },
      complete: function () {
        wx.hideLoading();
      }
    });
  },

  back: function () {
    this.setData({
      isShowResult: false
    })
  }

})

```

- 小程序的`data`，就是React的`state`
- 小程序通过`this.setData()`刷新页面状态，如同React的`this.setState()`
- 使用`wx.request()`做http请求
- 使用`wx.showToast()`显示一个提示
- 使用`wx.showLoading()`显示Loading
- 这里发现一个小程序的bug，在`wx.hideLoading()`会将Toast也消失掉。


至此大功告成！打开微信扫一扫文章开头的小程序码即可使用。
访问 https://github.com/wangyucode/Clipboard 查看完整源码

> 本文介绍如何利用`hexo-generator-search`插件为Hexo博客添加本地全文搜索

## 原理
`hexo-generator-search`实际上是根据网页内容生成了一个数据文件，格式是`XML`或者`JSON`。然后通过JS代码去匹配这个文件的内容，从而达到搜索的目的。

## 最终效果
![最终效果](/images/20170616_search_01.png "最终效果")
<!--more-->
## 步骤

### 安装 hexo-generator-search

```bash
$ npm install hexo-generator-search --save
```
### 配置

在`_config.yml`中添加

```yaml
search:
  path: search.xml
  field: post
```
### 使用
再次生成博客，就会发现`public`根目录下多了`search.xml`文件。

### 写一个搜索框：
使用`Bootstrap`框架的`modal`应该是极好的。
修改Hexo主题，（对此不了解的可以查看我的自定义Hexo主题的相关内容），在`layout.ejs`中添加一个modal：

```html
<%- partial('_partial/search-modal') %>
```

> 根据Bootstrap文档，modal需要尽量作为 body 标签的直接子元素。

`search-modal.ejs`的代码如下：
```html
<div class="modal fade" id="searchModal">
    <div class="modal-dialog modal-lg" role="document">
        <div class="modal-content">
            <div class="modal-body">
                <i class="fa fa-search" aria-hidden="true"></i> 搜索
                <input type="text" class="form-control" id="searchInput" placeholder="Keyword">
                <div class="search-content" id="searchResult"></div>
            </div>
        </div>
    </div>
</div>
```

> 链接加上`data-toggle="modal"  href="#searchModal"`属性即可实现modal的展开

